#!/usr/bin/env python3
"""One-time dump of W&B GRPO run histories into local JSONL files.

This script captures the training-time time-series we pulled from the W&B
project ``sneh2909-christ-university/house-md`` so the repository carries a
self-contained, auditable copy of the iteration log. Once the JSONLs in
``results/training_logs/`` exist, ``scripts/build_training_plots.py`` reads
them directly and you do not need a W&B account to regenerate the plots.

Re-running this script is idempotent: it overwrites the JSONLs with the same
rows. Update ``RUNS`` if you fetch newer histories from W&B.

Note on numerical precision
───────────────────────────
The values inlined below were transcribed from W&B's sampled run history
(rounded to ~4 decimal places). They are accurate enough to reproduce the
plots in ``docs/plots/`` and tell the iteration story, but for byte-exact
replays use the W&B Python API (``wandb.Api()``) against the run IDs in
``results/training_logs/runs.json``.
"""

from __future__ import annotations

import json
from pathlib import Path

OUT_DIR = Path(__file__).resolve().parents[1] / "results" / "training_logs"

# Selected key set — drop W&B internal fields and very-redundant min/max
# variants so the JSONLs stay compact and human-readable.
KEEP = (
    "step", "curriculum",
    "reward/mean", "reward/max", "reward/min", "reward/std",
    "loss", "kl",
    "batch/r1_accuracy_mean", "batch/r2_cost_mean", "batch/r6_anchoring_mean",
    "batch/r7_safety_mean", "batch/r8_format_mean",
    "batch/total_mean", "batch/correct_rate", "batch/timeout_rate",
    "batch/avg_cost", "batch/avg_turns", "batch/avg_tests",
    "batch/avg_diagnosis_turn",
    "batch/action_interview_rate", "batch/action_order_test_rate",
    "batch/action_examine_rate", "batch/action_update_differential_rate",
    "batch/action_diagnose_rate",
    "batch/diagnosis_mode_rate", "batch/unique_diagnoses",
    "batch/invalid_action_rate", "batch/fallback_action_rate",
)


def _r(step, curr, rm, rx, rn, rs, loss, kl, r1, r2, r6, r7, r8, total,
       cor, to, cost, turns, tests, dxt, ai, ao, ae, au, ad, dmr, uniq,
       inv, fb):
    """Compact constructor — positional args map to KEEP order."""
    return {
        "step": step, "curriculum": curr,
        "reward/mean": rm, "reward/max": rx, "reward/min": rn, "reward/std": rs,
        "loss": loss, "kl": kl,
        "batch/r1_accuracy_mean": r1, "batch/r2_cost_mean": r2,
        "batch/r6_anchoring_mean": r6, "batch/r7_safety_mean": r7,
        "batch/r8_format_mean": r8,
        "batch/total_mean": total, "batch/correct_rate": cor,
        "batch/timeout_rate": to,
        "batch/avg_cost": cost, "batch/avg_turns": turns,
        "batch/avg_tests": tests, "batch/avg_diagnosis_turn": dxt,
        "batch/action_interview_rate": ai,
        "batch/action_order_test_rate": ao,
        "batch/action_examine_rate": ae,
        "batch/action_update_differential_rate": au,
        "batch/action_diagnose_rate": ad,
        "batch/diagnosis_mode_rate": dmr, "batch/unique_diagnoses": uniq,
        "batch/invalid_action_rate": inv, "batch/fallback_action_rate": fb,
    }


