RUNS = {
    "grpo_10step_baseline.jsonl": ROWS_10STEP,
    "grpo_50step_main.jsonl": ROWS_50STEP_MAIN,
    "grpo_50step_compact.jsonl": ROWS_50STEP_COMPACT,
}


def main() -> None:
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    for name, rows in RUNS.items():
        path = OUT_DIR / name
        with path.open("w", encoding="utf-8") as f:
            for row in rows:
                f.write(json.dumps(row, separators=(",", ":")) + "\n")
        print(f"wrote {len(rows):>3} rows -> {path.relative_to(OUT_DIR.parent.parent)}")

    # Tiny stub for the failed run so consumers see all four iterations.
    failed = OUT_DIR / "grpo_5step_failed.jsonl"
    failed.write_text("", encoding="utf-8")
    print(f"wrote   0 rows -> {failed.relative_to(OUT_DIR.parent.parent)} (failed at startup)")


if __name__ == "__main__":
    main()
